qry:select.qry:xquery:
for $r in SQL('
{%?(#FILTER:@LEN='') {% %} {% MAXSIZE {%=#FILTER:@LEN %} %} %}
SELECT SEC.policy, TTA04_NOVEDADES.oi_novedad AS ID, TTA04_NOVEDADES.oi_personal_emp AS PARENT, ORG03_EMPRESAS.c_empresa AS CEMP, ORG03_EMPRESAS.d_empresa AS DEMP, PER02_PERSONAL_EMP.e_numero_legajo AS NLEG, PER01_PERSONAL.d_ape_y_nom AS NYA, TTA01_TIPOHORAS.c_tipohora AS CTH, TTA01_TIPOHORAS.d_tipohora AS DTH {%?($FILTER/@order!='') {% ,TTA04_NOVEDADES.{%=$FILTER/@order %} AS COL_ORDER %} {% ,TTA04_NOVEDADES.f_fecha AS f_fecha %} %}
FROM NMD_SECURITY(class=\'NucleusRH.Base.Personal.LegajoEmpresa.PERSONAL_EMP\') as SEC, TTA04_NOVEDADES, TTA01_TIPOHORAS, PER02_PERSONAL_EMP, PER01_PERSONAL, ORG03_EMPRESAS
JOIN TTA04_NOVEDADES.oi_personal_emp LEFT OUTER SEC.id, TTA04_NOVEDADES.oi_tipohora LEFT OUTER TTA01_TIPOHORAS.oi_tipohora, TTA04_NOVEDADES.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, PER02_PERSONAL_EMP.oi_personal INNER PER01_PERSONAL.oi_personal, PER02_PERSONAL_EMP.oi_empresa INNER ORG03_EMPRESAS.oi_empresa
WHERE 1=1 {%?($FILTER/@parent!='') {% AND PARENT={$FILTER/@parent} %} {% %} %} {%?($FILTER/@search!='') {% AND (contain(ucase(CEMP),{upper-case($FILTER/@search)}) OR contain(ucase(DEMP),{upper-case($FILTER/@search)}) OR contain(ucase(NLEG),{upper-case($FILTER/@search)}) OR contain(ucase(NYA),{upper-case($FILTER/@search)}) OR contain(ucase(CTH),{upper-case($FILTER/@search)}) OR contain(ucase(DTH),{upper-case($FILTER/@search)})) %} {% %} %}
{%?($FILTER/@order!='') {% ORDER BY COL_ORDER {%=iif($FILTER/@asc='1','asc','desc') %} %} {% ORDER BY f_fecha desc %} %}
')/ROWS/ROW

for $f in sql('
SELECT hp.oi_horario, hp.oi_horariopers, hp.oi_personal_emp, hp.f_fechaInicio, hp.f_fechaFin, hp.oi_escuadra, h.d_TipoHorario, h.c_horario
FROM TTA04_HorariosPers as hp, TTA02_Horarios as h
JOIN hp.oi_horario INNER h.oi_horario
WHERE 1 = 1
{%? (#PARAM:@f_Fin != '') {% AND ( {DateTime(#PARAM:@f_Fin)} >= hp.f_fechaInicio AND ( {DateTime(#PARAM:@f_Inicio)} < hp.f_fechaFin OR ISNULL(hp.f_fechaFin)
)
)
%} {% %} %}
{%? (#PARAM:@oi_personal_emps != '') {% AND hp.oi_personal_emp IN ({%= #PARAM:@oi_personal_emps%}) %} {% %} %}
ORDER BY oi_personal_emp ASC, f_fechaInicio ASC
')/ROWS/ROW

for $f in sql('
SELECT hp.oi_horario, hp.oi_horariopers, hp.oi_personal_emp, hp.f_fechaInicio, hp.f_fechaFin, hp.oi_escuadra, h.d_TipoHorario, h.c_horario
FROM TTA04_HorariosPers as hp, TTA02_Horarios as h
JOIN hp.oi_horario INNER h.oi_horario
WHERE 1 = 1
{%? (#PARAM:@f_Fin != '') {% AND ( {DateTime(#PARAM:@f_Fin)} >= hp.f_fechaInicio AND ( {DateTime(#PARAM:@f_Inicio)} < hp.f_fechaFin OR ISNULL(hp.f_fechaFin)
)
)
%} {% %} %}
{%? (#PARAM:@oi_personal_emps != '') {% AND hp.oi_personal_emp IN ({%= #PARAM:@oi_personal_emps%}) %} {% %} %}
ORDER BY oi_personal_emp ASC, f_fechaInicio ASC
')/ROWS/ROW
